import { useSelector } from "react-redux";

import Card from "../UI/Card";
import classes from "./Cart.module.css";
import CartItem from "./CartItem";

const Cart = (props) => {
  const CartQuantity = useSelector((state) => state.addToCart.items);
  // const CartTitle = useSelector((state) => state.addToCart.title);
  // const CartPrice = useSelector((state) => state.addToCart.price);

  // console.log(CartPrice);
  // console.log(CartTitle);
  // console.log(CartQuantity);

  return (
    <Card className={classes.cart}>
      <h2>Your Shopping Cart</h2>
      <ul>
        <CartItem
          item={{
            title: "sssss",
            quantity: 2,
            total: 2,
            price: 2,
          }}
        />
      </ul>
    </Card>
  );
};

export default Cart;
